class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = (
            process_priority if process_priority in _UNIX_NICE_VALUES else None
        )

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _get_popen_priority_kwargs(self) -> dict[str, t.Any]:
        if self.process_priority is None:
            return {}

        if WIN:
            import subprocess

            priority_class = getattr(
                subprocess, _WIN_PRIORITY_CLASSES[self.process_priority], None
            )

            if priority_class is None:
                return {}

            return {"creationflags": priority_class}

        return {}

    def _set_unix_priority(self) -> None:
        nice_increment = _UNIX_NICE_VALUES[self.process_priority]  # type: ignore[index]

        try:
            os.nice(nice_increment)
        except (AttributeError, OSError, PermissionError):
            pass

